// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

	// STRY0100152 
	if(isLoading){
		peformDurationCheck(newValue);
		return;
	}

	peformDurationCheck();

	function peformDurationCheck(newValue){
		var duration = getDateFromFormat(newValue, g_user_date_time_format);

		// STRY0091294
		var isSuspenseDateRequired = g_scratchpad.isSuspenseDateRequired;
		g_form.setMandatory('u_duration',isSuspenseDateRequired == 'true'); // To make mandatory

		// need to set the message even on load
		if (g_scratchpad.totalChildDuration >  duration){
//			g_form.showFieldMsg('u_duration', getMessage('Tasker - Warning: Parent duration shorter than the durations of subtasks'),'error', false);
// TODO -determine field and calcualation
//			g_form.showFieldMsg('u_duration_time_due', getMessage('The projected {0} of one (1) or more Subtasks exceeds the projected {1}  of this task').replace('{0}', g_scratchpad.suspense_date_label).replace('{1}',g_scratchpad.suspense_date_label),'warn', false);
		}

	}

}
